package inequivalent;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

class ClonePair88Method2Test {

    private final ClonePair88 subject = new ClonePair88();

    @Test
    void method2FindsLastExactOccurrence() {
        // Generated by Codex (gpt-5.4).
        char[] source = "abracadabra".toCharArray();
        char[] target = "abra".toCharArray();

        assertEquals(7, subject.method2(source, 0, source.length, target, 0, target.length, source.length));
    }

    @Test
    void method2DoesNotIgnoreCase() {
        // Generated by Codex (gpt-5.4).
        char[] source = "abRaCadABRA".toCharArray();
        char[] target = "ABRA".toCharArray();

        assertEquals(7, subject.method2(source, 0, source.length, target, 0, target.length, source.length));
        assertEquals(-1, subject.method2(source, 0, source.length, "abra".toCharArray(), 0, 4, source.length));
    }

    @Test
    void method2ReturnsMinusOneForNegativeFromIndex() {
        // Generated by Codex (gpt-5.4).
        char[] source = "hello".toCharArray();
        char[] target = "lo".toCharArray();

        assertEquals(-1, subject.method2(source, 0, source.length, target, 0, target.length, -1));
    }

    @Test
    void method2ReturnsClampedFromIndexForEmptyTarget() {
        // Generated by Codex (gpt-5.4).
        char[] source = "hello".toCharArray();
        char[] target = "x".toCharArray();

        assertEquals(5, subject.method2(source, 0, source.length, target, 0, 0, 99));
    }

    @Test
    void method2ThrowsNullPointerExceptionWhenSourceIsNullAndSearchMustProceed() {
        // Generated by Codex (gpt-5.4).
        char[] target = "he".toCharArray();

        assertThrows(NullPointerException.class, () -> subject.method2(null, 0, 3, target, 0, target.length, 0));
    }
}
